var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"타깃을 발견했다.","JPN":"ターゲットを発見した。","ENG":"Target located.","TWN":"目標已找到。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"이미 빼돌린 줄 알았는데, 이런 곳에 숨겨뒀었군.","JPN":"すでになくなっていると思っていたが、こんなところに隠しておいたとはな。","ENG":"I thought he already took it away, but he hid it here.","TWN":"還以為已經逃跑了，沒想到竟然藏在這種地方。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"본부, 들리나? 타깃 회수를 위해 지원병력을 요청한다.","JPN":"本部に伝える。ターゲットの回収のため、兵力の追加支援を求む。","ENG":"HQ, do you copy? Requesting reinforcements to assist with the retrieval.","TWN":"總部，能聽到我說話嗎？為了帶回目標，請求增援。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"이런. 송신상태가 불량인가?","JPN":"くっ、通信状況が芳しくないようだ。","ENG":"Damn. Are the comms out?","TWN":"可惡。傳輸訊號不好嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"뭐야? 무슨 일이야?","JPN":"なんだ？　何が起きた？","ENG":"What? What’s going on?","TWN":"什麼？怎麼了？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"매복이다! 놈이 눈치챘어!","JPN":"待ち伏せだ！　奴に気づかれていたぞ！","ENG":"It's an ambush! We've been found!","TWN":"有埋伏！發現那傢伙了！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"쏴! 쏘라고!","JPN":"撃て！　撃ちまくれ！","ENG":"Fire! Return fire!","TWN":"射擊！快射擊！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식체한테 당한 건 아니네요. 이건 탄환이 뚫고 간 자국이에요.","JPN":"これは侵食体にやられた傷跡じゃありません。弾丸に撃ち抜かれた痕です。","ENG":"This wasn't a C.O.'s doing. These are bullet holes.","TWN":"不是被侵蝕體襲擊的。這是子彈穿過的痕跡。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"와아, 이 사람은 폐를 관통 당했네요.","JPN":"わあ、この人は肺に穴を開けられたみたいです。","ENG":"Wow, this person got his lungs pierced.","TWN":"哇，這傢伙的肺被打穿了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"분명 엄청 괴로워하면서 죽었겠죠?","JPN":"きっと、すごく苦しい死に方をしたでしょうね。","ENG":"He must've suffered a lot.","TWN":"他一定死得很痛苦吧？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금 블랙박스기록 확인했어. 선발대는 누군가의 습격을 받은 게 맞아.","JPN":"さっきブラックボックスの記録は確認した。先発隊は何者かに襲撃を受けたに違いない。","ENG":"I just checked the black box records. The advance party was ambushed by someone.","TWN":"我剛剛查了一下黑盒記錄。先遣隊確實被人襲擊了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"습격자는 아마도 우리가 쫓고 있는 의뢰 타깃이겠지.","JPN":"襲撃したのは……おそらく私たちが追いかけているターゲットと同じ人物のはずだ。","ENG":"The ambusher must be the target we're after.","TWN":"襲擊者很可能就是我們所追查的委託目標。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"무기를 가지고 있다면, 평화적인 방법으로 데려가긴 어렵겠네요.","JPN":"相手が武器を持っているなら、平和的に連れて帰るのは難しそうですね。","ENG":"If this person is armed, we might face some resistance.","TWN":"如果他攜帶著武器，我們很難和平地帶走他。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…그래. 상처없이 제압하라곤 안 할 테니 죽이지만 마.","JPN":"……そうだな。無傷でとは言わないが、生かして捕らえろ。","ENG":"...Yeah. I won't tell you not to hurt him, but just don't kill him.","TWN":"……我知道。讓他受點傷沒什麼關係，只要不殺掉就可以了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"전 다쳐도 돼요. 원하시면 최대한 건강한 상태로 붙잡아볼게요.","JPN":"私はいくら怪我をしても大丈夫ですので、相手にはできるだけ傷を与えずに捕まえてみます。","ENG":"I don't mind getting hurt. I'll try to take him down without hurting him.","TWN":"我倒是不介意受傷。如果是你的要求，我會盡力不傷著他。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그 분이 만약 스펜서를 노린다면, 저도 공격하는 수밖에 없겠지만요.","JPN":"でもスペンサーさんが狙われたその時は、しかたないので攻撃しますよ。","ENG":"But if he attacks you, Spencer, I'll have no choice but to fight back.","TWN":"但如果他要攻擊你，史賓瑟，那我也只能還擊了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"목숨을 내버리면서까지 무리할 일은 아니야.","JPN":"命をかけてもらうほどのことではない。","ENG":"It's not worth throwing away your life over.","TWN":"不需要你犧牲自己。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 좋은 카운터 능력도 이터니움이 떨어져버리면 쓸 수 없게 된다며?","JPN":"素晴らしいカウンターの能力を持っているのに、エタニウムがないと発動できなくなるんだって？","ENG":"I hear you can't use your remarkable Counter ability if you run out of Eternium, no?","TWN":"當永恆之金耗盡時，制裁者就無法使用能力了吧？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"무슨 위험한 일을 하든, 일단 살고 봐야지. 안 그래?","JPN":"どんな危険な仕事だろうと、死んでしまったら意味がない、違うか？","ENG":"Whatever dangerous thing you do, live to fight another day first, okay?","TWN":"無論你準備冒什麼險，先考慮活下來的事情。好嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서는 차가운 척하지만 실은 마음이 따뜻한 사람이네요.","JPN":"スペンサーさんって、冷たいようで実は温かい方なんですね。","ENG":"You act cold but you're actually a kind person, Spencer.","TWN":"史賓瑟，你雖然看起來冷酷，但其實是個溫柔的人呢。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"마음대로 생각해.","JPN":"私はどう思われたっていい。","ENG":"Whatever.","TWN":"隨你怎麼想。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서? 선발대가 갖고 있던 총을 챙기려고요?","JPN":"スペンサーさん？　どうして先発隊の銃を手に取るんですか？","ENG":"Spencer? You're picking up the advance party's gun?","TWN":"史賓瑟？你拿著先遣隊的槍做什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그건 침식체한텐 별로 효과 없을 텐데.","JPN":"それは、たぶん侵食体には効かないと思いますよ。","ENG":"It won't be very useful against C.O.s.","TWN":"這東西對侵蝕體作用不大。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"역시 그렇지?","JPN":"やはりそうか？","ENG":"Yeah, I know.","TWN":"果然嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}}]`);export{e as default};